  '사각 두평': { product: '미니멀러그', shape: '사각', size: '200x250', displayName: '사각 두평 (200x250)', sku: 'MR-SQ-200X250' },
  '도어 S': { product: '미니멀러그', shape: '사각', size: '48x80', displayName: '도어 S (48x80)', sku: 'MR-DR-48X80' },
  '도어 M': { product: '미니멀러그', shape: '사각', size: '60x100', displayName: '도어 M (60x100)', sku: 'MR-DR-60X100' },
  '도어 L': { product: '미니멀러그', shape: '사각', size: '78x130', displayName: '도어 L (78x130)', sku: 'MR-DR-78X130' },
  '주방매트(라운드)': { product: '미니멀러그', shape: '사각', size: '50x150(라운드)', displayName: '주방매트(라운드)', sku: 'MR-RD-50X150' },
  '발매트': { product: '미니멀러그', shape: '사각', size: '40x60', displayName: '발매트 (40x60)', sku: 'MR-SQ-40X60' },
  '원형 L': { product: '미니멀러그', shape: '원형', size: '150', displayName: '원형 L (150∅)', sku: 'MR-CR-150' },
  '원형 M': { product: '미니멀러그', shape: '원형', size: '100', displayName: '원형 M (100∅)', sku: 'MR-CR-100' },
  '타원 L': { product: '미니멀러그', shape: '타원', size: '200x300', displayName: '타원 L (200x300)', sku: 'MR-OV-200X300' },
  '타원 M': { product: '미니멀러그', shape: '타원', size: '150x225', displayName: '타원 M (150x225)', sku: 'MR-OV-150X225' },
