// 그레인러그 품목 매핑 (G_ 접두사)
export const grainRugMapping: Record<string, ItemMapping> = {
  'G_점보': { product: '그레인러그', shape: '사각', size: '200x300', displayName: 'G_점보', sku: 'GR-SQ-200X300' },
  'G_한평': { product: '그레인러그', shape: '사각', size: '200x250', displayName: 'G_한평', sku: 'GR-SQ-200X250' },
  'G_주방매트_사각': { product: '그레인러그', shape: '주방매트', size: '사각', displayName: 'G_주방매트_사각', sku: 'GR-KT-SQ' },
