  'G_도어 M': { product: '그레인러그', shape: '도어매트', size: 'M', displayName: 'G_도어 M', sku: 'GR-DR-M' },
  'G_원형 L': { product: '그레인러그', shape: '원형', size: 'L', displayName: 'G_원형 L', sku: 'GR-CR-L' },
  'G_원형 M': { product: '그레인러그', shape: '원형', size: 'M', displayName: 'G_원형 M', sku: 'GR-CR-M' },
  'G_타원 L': { product: '그레인러그', shape: '타원', size: 'L', displayName: 'G_타원 L', sku: 'GR-OV-L' },
  'G_타원 M': { product: '그레인러그', shape: '타원', size: 'M', displayName: 'G_타원 M', sku: 'GR-OV-M' },
  'G_소파패드 3인용': { product: '그레인러그', shape: '소파패드', size: '3인용', displayName: 'G_소파패드 3인용', sku: 'GR-SP-3P' },
  'G_소파패드 2인용': { product: '그레인러그', shape: '소파패드', size: '2인용', displayName: 'G_소파패드 2인용', sku: 'GR-SP-2P' },
