export const sisalRugMapping: Record<string, ItemMapping> = {
  'F_발매트': { product: '사이잘룩러그', shape: '발매트', size: '450x650', displayName: 'F_발매트 (450x650)', sku: 'SR-450X650' },
  'F_주방매트': { product: '사이잘룩러그', shape: '주방매트', size: '650x2000', displayName: 'F_주방매트 (650x2000)', sku: 'SR-650X2000' },
  'F_S': { product: '사이잘룩러그', shape: '사각', size: '100x150', displayName: 'F_S (100x150)', sku: 'SR-100X150' },
  'F_M': { product: '사이잘룩러그', shape: '사각', size: '150x200', displayName: 'F_M (150x200)', sku: 'SR-150X200' },
  'F_L': { product: '사이잘룩러그', shape: '사각', size: '200x250', displayName: 'F_L (200x250)', sku: 'SR-200X250' },
  'F_XL': { product: '사이잘룩러그', shape: '사각', size: '200x300', displayName: 'F_XL (200x300)', sku: 'SR-200X300' },
}

// 시어서커 품목 매핑 (cm 단위)
export const seersuckerMapping: Record<string, ItemMapping> = {
  // 러그
  'S_사각 반평': { product: '시어서커', shape: '러그', size: '100x150', displayName: 'S_사각 반평 (100x150)', sku: 'SE-SQ-100X150' },
  'S_사각 한평': { product: '시어서커', shape: '러그', size: '150x200', displayName: 'S_사각 한평 (150x200)', sku: 'SE-SQ-150X200' },
  'S_사각 두평': { product: '시어서커', shape: '러그', size: '200x250', displayName: 'S_사각 두평 (200x250)', sku: 'SE-SQ-200X250' },
  'S_점보': { product: '시어서커', shape: '러그', size: '200x300', displayName: 'S_점보 (200x300)', sku: 'SE-JM-200X300' },
  // 소파커버
  '소파패드 S': { product: '시어서커', shape: '소파커버', size: '65x180', displayName: '소파패드 S (65x180)', sku: 'SE-SP-65X180' },
  '소파패드 M': { product: '시어서커', shape: '소파커버', size: '65x240', displayName: '소파패드 M (65x240)', sku: 'SE-SP-65X240' },
  '소파패드 L': { product: '시어서커', shape: '소파커버', size: '90x200', displayName: '소파패드 L (90x200)', sku: 'SE-SP-90X200' },
  // 매트커버
  '매트패드 SS': { product: '시어서커', shape: '매트커버', size: '110x200', displayName: '매트패드 SS (110x200)', sku: 'SE-MP-110X200' },
  '매트패드 Q': { product: '시어서커', shape: '매트커버', size: '150x200', displayName: '매트패드 Q (150x200)', sku: 'SE-MP-150X200' },
  '매트패드 K': { product: '시어서커', shape: '매트커버', size: '160x200', displayName: '매트패드 K (160x200)', sku: 'SE-MP-160X200' },
  '매트패드 LK': { product: '시어서커', shape: '매트커버', size: '180x200', displayName: '매트패드 LK (180x200)', sku: 'SE-MP-180X200' },
