// 미니멀 방석/쿠션 품목 매핑 (cost_data의 product는 "미니멀 쿠션"으로 저장됨)
// "미니멀 방석"과 "미니멀펫쿠션" 세트 모두 이 매핑 사용
export const minimalMatMapping: Record<string, ItemMapping> = {
  '방석': { product: '미니멀 쿠션', shape: '방석', size: '미니멀 방석', displayName: '방석', sku: 'MM-MAT' },
  '방석 커버': { product: '미니멀 쿠션', shape: '방석', size: '커버', displayName: '방석 커버', sku: 'MM-MAT-C' },
  '방석 충전재': { product: '미니멀 쿠션', shape: '방석', size: '충전재', displayName: '방석 충전재', sku: 'MM-MAT-F' },
  '펫쿠션_M': { product: '미니멀 쿠션', shape: '펫쿠션', size: 'M', displayName: '펫쿠션_M', sku: 'MM-PET-M' },
  '펫쿠션_L': { product: '미니멀 쿠션', shape: '펫쿠션', size: 'L', displayName: '펫쿠션_L', sku: 'MM-PET-L' },
  '커버_M': { product: '미니멀 쿠션', shape: '펫쿠션', size: '커버 M', displayName: '커버_M', sku: 'MM-PET-C-M' },
  '커버_L': { product: '미니멀 쿠션', shape: '펫쿠션', size: '커버 L', displayName: '커버_L', sku: 'MM-PET-C-L' },
  '충전재_M': { product: '미니멀 쿠션', shape: '펫쿠션', size: '충전재 M', displayName: '충전재_M', sku: 'MM-PET-F-M' },
  '충전재_L': { product: '미니멀 쿠션', shape: '펫쿠션', size: '충전재 L', displayName: '충전재_L', sku: 'MM-PET-F-L' },
}

// 티가든 블랭킷 품목 매핑
export const blanketMapping: Record<string, ItemMapping> = {
  '블랭킷_M': { product: '티가든 블랭킷', shape: '블랭킷', size: 'M', displayName: '블랭킷_M', sku: 'BK-M' },
  '블랭킷_L': { product: '티가든 블랭킷', shape: '블랭킷', size: 'L', displayName: '블랭킷_L', sku: 'BK-L' },
}

// 통합 매핑
export const allItemMappings = {
  ...minimalRugMapping,
  ...grainRugMapping,
  ...sisalRugMapping,
  ...seersuckerMapping,
  ...minimalMatMapping,
  ...blanketMapping,
}

// 품목명 리스트 파싱 ("점보, 사각 한평, 도어 S" → ["점보", "사각 한평", "도어 S"])
// 수량 포함 형식도 지원: "점보x2, 사각 한평x1" → ["점보x2", "사각 한평x1"]
export function parseSetDetails(setDetails: string): string[] {
  return setDetails
    .split(',')
    .map(item => item.trim())
    .filter(item => item.length > 0)
}

// 품목명과 수량 파싱 ("점보x2" → { name: "점보", qty: 2 })
export interface ItemWithQty {
  name: string
  qty: number
}

export function parseItemWithQty(item: string): ItemWithQty {
  const match = item.match(/^(.+?)x(\d+)$/)
  if (match) {
    return { name: match[1].trim(), qty: parseInt(match[2]) }
  }
  return { name: item.trim(), qty: 1 }
}

// 품목명과 수량을 문자열로 변환 ({ name: "점보", qty: 2 } → "점보x2")
export function formatItemWithQty(name: string, qty: number): string {
  return qty > 1 ? `${name}x${qty}` : name
}

// 구성 품목에서 제품 정보 가져오기
export function getItemInfo(itemName: string): ItemMapping | null {
  return allItemMappings[itemName] || null
}

// 제품명 변환 (세트 테이블 product → cost_data product)
function normalizeProductName(product: string): string {
  const mapping: Record<string, string> = {
    '미니멀 방석': '미니멀 쿠션',
    '미니멀펫쿠션': '미니멀 쿠션',
  }
  return mapping[product] || product
}

// 제품별 사용 가능한 품목 리스트
export function getAvailableItemsForProduct(product: string): string[] {
  const normalizedProduct = normalizeProductName(product)
  return Object.entries(allItemMappings)
    .filter(([_, info]) => info.product === normalizedProduct)
    .map(([name]) => name)
}

