}

// 통합 매핑
export const allItemMappings = {
  ...minimalRugMapping,
  ...grainRugMapping,
  ...sisalRugMapping,
  ...seersuckerMapping,
  ...minimalMatMapping,
  ...blanketMapping,
}

// 품목명 리스트 파싱 ("점보, 사각 한평, 도어 S" → ["점보", "사각 한평", "도어 S"])
// 수량 포함 형식도 지원: "점보x2, 사각 한평x1" → ["점보x2", "사각 한평x1"]
export function parseSetDetails(setDetails: string): string[] {
  return setDetails
    .split(',')
    .map(item => item.trim())
    .filter(item => item.length > 0)
}

// 품목명과 수량 파싱 ("점보x2" → { name: "점보", qty: 2 })
export interface ItemWithQty {
  name: string
  qty: number
}

export function parseItemWithQty(item: string): ItemWithQty {
  const match = item.match(/^(.+?)x(\d+)$/)
  if (match) {
    return { name: match[1].trim(), qty: parseInt(match[2]) }
  }
  return { name: item.trim(), qty: 1 }
}

// 품목명과 수량을 문자열로 변환 ({ name: "점보", qty: 2 } → "점보x2")
export function formatItemWithQty(name: string, qty: number): string {
  return qty > 1 ? `${name}x${qty}` : name
}

// 구성 품목에서 제품 정보 가져오기
export function getItemInfo(itemName: string): ItemMapping | null {
  return allItemMappings[itemName] || null
}

// 제품명 변환 (세트 테이블 product → cost_data product)
function normalizeProductName(product: string): string {
  const mapping: Record<string, string> = {
    '미니멀 방석': '미니멀 쿠션',
    '미니멀펫쿠션': '미니멀 쿠션',
  }
  return mapping[product] || product
}

// 제품별 사용 가능한 품목 리스트
export function getAvailableItemsForProduct(product: string): string[] {
  const normalizedProduct = normalizeProductName(product)
  return Object.entries(allItemMappings)
    .filter(([_, info]) => info.product === normalizedProduct)
    .map(([name]) => name)
}

