import { supabase } from '@/lib/supabase'
import SKUPageClient from '@/components/SKUPageClient'

export const dynamic = 'force-dynamic'
export const revalidate = 0

interface ProductSKU {
  barcode: string
  sku_name: string
  product_category: string | null
  is_set: boolean
  selling_price: number | null
}

interface SetComposition {
  set_barcode: string
  component_name: string
  component_barcode: string | null
  quantity: number
}

export default async function SKUPage() {
  // product_sku 테이블에서 모든 SKU 가져오기 (단품 + 세트)
  const { data: skuData, error } = await supabase
    .from('product_sku')
    .select('barcode, sku_name, product_category, is_set, selling_price')
    .order('barcode', { ascending: true })

  if (error) {
    console.error('Error fetching SKU data:', error)
    return <div>데이터를 불러오는데 실패했습니다.</div>
  }

  // 세트 구성품 데이터 가져오기
  const { data: compositionData } = await supabase
    .from('set_composition')
    .select('set_barcode, component_name, component_barcode, quantity')

  // 세트별 구성품 맵 생성
  const compositionMap = new Map<string, SetComposition[]>()
  if (compositionData) {
    (compositionData as SetComposition[]).forEach(item => {
      if (!compositionMap.has(item.set_barcode)) {
        compositionMap.set(item.set_barcode, [])
      }
      compositionMap.get(item.set_barcode)!.push(item)
    })
  }

  // 클라이언트 컴포넌트 형식에 맞게 데이터 변환
  const formattedData = (skuData as ProductSKU[]).map(item => ({
    sku: item.barcode,
    product_name: item.sku_name,
    product_category: item.product_category,
    is_set: item.is_set,
    selling_price: item.selling_price,
    composition: item.is_set ? compositionMap.get(item.barcode) || [] : []
  }))

  return <SKUPageClient data={formattedData} />
}

'use client'

import { useState, useEffect } from 'react'
import * as XLSX from 'xlsx'
import ProductDailyTable from '@/components/ProductDailyTable'

interface Props {
  allData: {
    datesByMonth: Record<string, string[]>
    barcodes: string[]
    barcodeInfo: Record<string, any>
    dailySalesMap: Record<string, Record<string, number>>
    dreamBarcodes: string[]
    dreamSalesMap: Record<string, Record<string, number>>
    tuminBarcodes: string[]
    tuminSalesMap: Record<string, Record<string, number>>
  }
}

export default function ClientPage({ allData }: Props) {
  const availableMonths = Object.keys(allData.datesByMonth).sort()

  // 현재 월을 기본값으로 설정 (YYYY-MM 형식)
  const now = new Date()
  const currentMonth = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`
  const defaultMonth = availableMonths.includes(currentMonth)
    ? currentMonth
    : availableMonths[availableMonths.length - 1] || ''

  const [selectedMonth, setSelectedMonth] = useState(defaultMonth)
  const [selectedWarehouse, setSelectedWarehouse] = useState<'all' | 'dream' | 'tumin'>('all')

  // 선택된 월의 데이터만 필터링
  const filteredDatesByMonth = selectedMonth
    ? { [selectedMonth]: allData.datesByMonth[selectedMonth] }
    : {}

  // 창고별 필터링
  const filteredBarcodes = selectedWarehouse === 'all'
    ? allData.barcodes
    : selectedWarehouse === 'dream'
    ? allData.dreamBarcodes
    : allData.tuminBarcodes

  const filteredDailySalesMap = selectedWarehouse === 'all'
    ? allData.dailySalesMap
    : selectedWarehouse === 'dream'
    ? allData.dreamSalesMap
    : allData.tuminSalesMap

  const formatMonth = (monthStr: string) => {
    const [year, month] = monthStr.split('-')
    return `${year}년 ${parseInt(month)}월`
  }

