// 러그 카테고리 (제조사=드림 발주 대상)
const RUG_CATEGORIES = ['미니멀러그', '사이잘룩러그', '그레인러그', '시어서커', '티가든러그']

// 러그 제품 바코드 패턴 체크
function isRugBarcode(sku: string): boolean {
  if (!sku) return false
  const s = sku.trim()

  // 미니멀러그: LE10... (단, LE104는 그레인러그)
  if (s.startsWith('LE10') && !s.startsWith('LE104')) return true

  // 그레인러그: LE104...
  if (s.startsWith('LE104')) return true

  // 사이잘룩러그: LF...
  if (s.startsWith('LF')) return true

  // 시어서커: LC...
  if (s.startsWith('LC')) return true

  // 티가든러그: LEC10000... (티가든 블랭킷 LEC1012, LEC101X는 제외)
  if (s.startsWith('LEC10000')) return true

  return false
}

function isRugProduct(o: { 상품명?: string; SKU?: string }): boolean {
  const name = (o.상품명 || '') + ' ' + (o.SKU || '')
  const sku = (o.SKU || '').trim()

  // 1. 비러그 제품 제외 (3PL만)
  if (name.includes('스와치') || name.includes('방석') || name.includes('쿠션') || name.includes('블랭킷')) return false

  // 2. 바코드로 러그 제품 판별
  if (isRugBarcode(sku)) return true

  // 3. 제품명으로 판별
  return RUG_CATEGORIES.some(cat => name.includes(cat))
}

