const fetchStats = async () => {
  try {
    // 전체 날짜별 통계 - SQL 뷰 사용
    const { data: statsData, error: statsError } = await supabase
      .from('daily_shipment_stats_view')
      .select('*')
      .order('upload_date', { ascending: false })

    if (!statsError && statsData) {
      setRecentDates(statsData as DailyStats[])

      // 뷰 데이터로 금일/금주/금월 통계 계산
      const thisMonday = getThisMonday()
      const thisMonthStart = getThisMonthStart()

      // 금일 통계
      const todayStat = statsData.find(s => s.upload_date === today)
      if (todayStat) {
        setTodayStats({
          upload_date: today,
          total_orders: todayStat.total_orders,
          total_quantity: todayStat.total_quantity
        })
      } else {
        setTodayStats({ upload_date: today, total_orders: 0, total_quantity: 0 })
      }

      // 금주 통계 (월요일부터)
      const weekData = statsData.filter(s => s.upload_date >= thisMonday)
      const weekOrders = weekData.reduce((sum, s) => sum + s.total_orders, 0)
      const weekQty = weekData.reduce((sum, s) => sum + s.total_quantity, 0)
      setWeekStats({
        upload_date: thisMonday,
        total_orders: weekOrders,
        total_quantity: weekQty
      })

      // 금월 통계
      const monthData = statsData.filter(s => s.upload_date >= thisMonthStart)
      const monthOrders = monthData.reduce((sum, s) => sum + s.total_orders, 0)
      const monthQty = monthData.reduce((sum, s) => sum + s.total_quantity, 0)
      setMonthStats({
        upload_date: thisMonthStart,
        total_orders: monthOrders,
        total_quantity: monthQty
      })
    }
  } catch (error) {
    console.error('통계 조회 실패:', error)
  }
}

// 파일 선택
const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
  const selectedFile = e.target.files?.[0]
  if (selectedFile) {
    setFile(selectedFile)
    parseExcel(selectedFile)
  }
}

// 오더코드에서 날짜 추출 (O20260323-00297 → 2026-03-23)
const extractDateFromOrderCode = (orderCode: string): string => {
  try {
    // O 다음 8자리 추출 (YYYYMMDD)
    const dateStr = orderCode.substring(1, 9)
    const year = dateStr.substring(0, 4)
    const month = dateStr.substring(4, 6)
    const day = dateStr.substring(6, 8)
    return `${year}-${month}-${day}`
  } catch (error) {
    console.error('날짜 추출 실패:', error)
    return new Date().toISOString().split('T')[0] // 실패 시 오늘 날짜
  }
}

