  if (!file) {

// 엑셀 파싱
const parseExcel = (file: File) => {
  // 파일 유효성 검증
  if (!file) {
    alert('파일을 선택해주세요')
    return
  }
  if (file.size === 0) {
    alert('빈 파일입니다. 파일을 다시 확인해주세요')
    return
  }

  // 확장자 검증
  const validExtensions = ['.xlsx', '.xls', '.csv']
  const isValidExt = validExtensions.some(ext => file.name.toLowerCase().endsWith(ext))
  if (!isValidExt) {
    alert('엑셀 파일(.xlsx, .xls) 또는 CSV 파일만 업로드 가능합니다')
    return
  }

  const reader = new FileReader()

  reader.onerror = () => {
    console.error('파일 읽기 실패')
    alert('파일을 읽을 수 없습니다. 파일이 손상되었거나 권한이 없습니다.')
  }

  reader.onload = (e) => {
    try {
      const data = new Uint8Array(e.target?.result as ArrayBuffer)

      if (data.length === 0) {
        alert('파일 내용이 비어있습니다')
        return
      }

      // 파일 헤더 검증
      // .xlsx (ZIP): 50 4B (PK)
      // .xls (BIFF): D0 CF 11 E0
      const isZip = data[0] === 0x50 && data[1] === 0x4B
      const isBiff = data[0] === 0xD0 && data[1] === 0xCF
      const isCSV = file.name.toLowerCase().endsWith('.csv')

      if (!isZip && !isBiff && !isCSV) {
        alert('올바른 엑셀 파일이 아닙니다.\n\n파일이 손상되었거나 다른 형식입니다.\n엑셀에서 파일을 열어 .xlsx로 다시 저장 후 시도해주세요.')
        return
      }

      const workbook = XLSX.read(data, {
        type: 'array',
        cellDates: false,
        cellNF: false,
        cellHTML: false,
      })

      if (!workbook.SheetNames || workbook.SheetNames.length === 0) {
        alert('엑셀 파일에 시트가 없습니다')
        return
      }

      const sheetName = workbook.SheetNames[0]
      const worksheet = workbook.Sheets[sheetName]
      const jsonData = XLSX.utils.sheet_to_json(worksheet, { defval: '' }) as any[]

      if (jsonData.length === 0) {
        alert('파일에 데이터가 없습니다')
        return
      }

      const parsed: ShipmentData[] = jsonData.map((row) => ({
        order_code: row['오더코드'] || '',
        order_memo: row['상품별 메모1'] || '',
        distributor: row['발주 타입'] || '',
        sku: row['고유코드'] || '',
        product_name: row['판매상품명'] || '',
        quantity: parseInt(row['수량']) || 0,
        courier: row['택배사'] || '',
        tracking_no: row['송장번호'] || ''
      }))

      setParsedData(parsed)
    } catch (error: any) {
      console.error('엑셀 파싱 실패:', error)

      // 에러 종류별 메시지
      let message = '엑셀 파일 읽기에 실패했습니다.'
      const errMsg = error?.message || ''

      if (errMsg.includes('Bad uncompressed size')) {
        message = '파일이 손상되었거나 잘못된 형식입니다.\n\n해결 방법:\n1. 엑셀에서 파일을 다시 열어서 "다른 이름으로 저장" → .xlsx로 저장\n2. 파일을 다시 다운로드'
      } else if (errMsg.includes('Unsupported')) {
        message = '지원되지 않는 파일 형식입니다. .xlsx 또는 .xls 파일을 사용해주세요.'
      } else if (errMsg.includes('password')) {
        message = '암호로 보호된 파일은 열 수 없습니다. 암호를 해제 후 다시 시도해주세요.'
      }

      alert(message)
    }
  }

