    const dataToInsert = parsedData.map(item => ({
      ...item,
      upload_date: extractDateFromOrderCode(item.order_code)
    }))

    // 업로드할 데이터의 고유 날짜 추출
    const uploadDates = [...new Set(dataToInsert.map(item => item.upload_date))]

    // 중복 날짜 확인
    const { data: existingDates, error: checkError } = await supabase
      .from('daily_shipment_data')
      .select('upload_date')
      .in('upload_date', uploadDates)

    if (checkError) {
      console.error('중복 확인 실패:', checkError)
      alert('중복 확인 중 오류가 발생했습니다.')
      setIsUploading(false)
      return
    }

    // 중복된 날짜가 있는지 확인
    if (existingDates && existingDates.length > 0) {
      const duplicateDates = [...new Set(existingDates.map(d => d.upload_date))].sort()
      alert(`⚠️ 이미 업로드된 날짜가 있습니다:\n\n${duplicateDates.join('\n')}\n\n중복된 날짜의 데이터를 먼저 삭제한 후 다시 업로드해주세요.`)
      setIsUploading(false)
      return
    }

    // 중복이 없으면 저장 진행
    const { error } = await supabase
      .from('daily_shipment_data')
      .insert(dataToInsert)

    if (error) {
      console.error('저장 실패:', error)
      alert('저장 중 오류가 발생했습니다: ' + error.message)
      return
    }

    // sales_orders 테이블에도 자동 저장 (택배건수 집계용)
    // 송장번호가 있는 데이터만 저장 + 중복 제거 (합배송 처리)
    const salesOrdersDataAll = dataToInsert
      .filter(item => item.tracking_no && item.tracking_no.trim() !== '')
      .map(item => {
        // distributor → warehouse 매핑
        // "드림산업", "투민글로벌" 등으로 변환
        let warehouse = '투민글로벌' // 기본값
        if (item.distributor && item.distributor.includes('드림')) {
          warehouse = '드림산업'
        } else if (item.distributor && item.distributor.includes('투민')) {
          warehouse = '투민글로벌'
        }

        return {
          order_date: item.upload_date,
          warehouse: warehouse,
          barcode: item.tracking_no,
          order_number: item.order_code || item.tracking_no,
          quantity: item.quantity || 1,
          note: item.product_name || '',
          order_type: '일반',
          is_set: false,
          created_by: 'shipment_auto'
        }
      })

    // 송장번호로 중복 제거 (합배송은 택배건수 1건으로 처리)
    const uniqueTrackingNos = new Set<string>()
    const salesOrdersData = salesOrdersDataAll.filter(item => {
      if (uniqueTrackingNos.has(item.barcode)) {
        return false // 중복 제거
      }
      uniqueTrackingNos.add(item.barcode)
      return true
    })

    if (salesOrdersData.length > 0) {
      const { error: salesOrdersError } = await supabase
        .from('sales_orders')
        .insert(salesOrdersData)

      if (salesOrdersError) {
        console.error('sales_orders 저장 실패:', salesOrdersError)
        // 출고 데이터는 저장되었으므로 경고만 표시
        alert(`⚠️ 출고 데이터는 저장되었으나, 택배건수 집계(sales_orders) 저장 중 오류가 발생했습니다.\n\n${salesOrdersError.message}\n\n출고 현황은 정상적으로 표시되지만, 판매량 대시보드의 택배건수는 수동으로 업데이트해야 할 수 있습니다.`)
      } else {
        console.log(`✓ sales_orders에 ${salesOrdersData.length}건 자동 저장 완료`)
      }
    }

    alert(`${parsedData.length}건의 데이터가 저장되었습니다!${salesOrdersData.length > 0 ? `\n(택배건수 ${salesOrdersData.length}건 자동 집계)` : ''}`)

    // 초기화
    setFile(null)
    setParsedData([])

    // 통계 새로고침
    await fetchStats()
  } catch (error) {
    console.error('저장 중 오류:', error)
    alert('저장 중 오류가 발생했습니다.')
  } finally {
    setIsUploading(false)
  }
}

